+    DetectedEnvironment {
+        wezterm: WeztermInfo {
+            version: None,
+            socket_path: None,
+            is_running: false,
+            capabilities: WeztermCapabilities::default(),
+        },
+        shell: ShellInfo {
+            shell_path: Some("/bin/zsh".into()),
+            shell_type: Some("zsh".into()),
+            version: None,
+            config_file: None,
+            osc_133_enabled: false,
+        },
+        agents,
+        remotes,
+        system: SystemInfo {
+            os: "linux".into(),
