+fn checkpoint_count(db_path: &str) -> i64 {
+    let conn = Connection::open(db_path).expect("open db");
+    conn.query_row("SELECT COUNT(*) FROM session_checkpoints", [], |row| {
+        row.get::<_, i64>(0)
+    })
+    .expect("count checkpoints")
+}
