+async fn e2e_snapshot_dedup_retention_and_detect_cycle() {
+    let run_start = Instant::now();
+    let mut report = E2ETestReport {
+        test_name: "e2e_snapshot_dedup_retention_and_detect_cycle".to_string(),
+        phases: Vec::new(),
